#include "HackComponent.h"

void UHackComponent::StartHack()
{
    CurrentTarget = TargetActor;
    GetWorld()->GetTimerManager().SetTimer(HackTimerHandle, this, &UHackComponent::FinishHack, 1.0f, false);
}

